func dartInnerSignature(node *sitter.Node) *sitter.Node {
	for _, inner := range []string{"function_signature", "getter_signature", "setter_signature"} {
		if child := firstNamedChildOfType(node, inner); validNode(child) {
			return child
		}
	}
