297	func fitAgentSearchResults(results []sem.SearchResult, budget int) []byte {
298		if budget <= 0 {
299			return renderAgentSearchResults(results, nil)
300		}
301		for count := len(results); count > 0; count-- {
302			available := budget - (count - 1)
303			if available <= 0 {
304				continue
305			}
306			resultBudgets := rankedAgentSearchBudgets(count, available)
307			formatted := renderAgentSearchResults(results[:count], resultBudgets)
308			if len(formatted) <= budget {
309				return formatted
310			}
311		}
312		return nil
313	}
