315	func rankedAgentSearchBudgets(count, budget int) []int {
316		if count <= 0 {
317			return nil
318		}
319		budgets := make([]int, count)
320		minimum := minIntCLI(128, budget/count)
321		remaining := budget - minimum*count
322		weightTotal := count * (count + 1) / 2
323		allocated := 0
324		for index := range budgets {
325			extra := 0
326			if weightTotal > 0 {
327				extra = remaining * (count - index) / weightTotal
328			}
329			budgets[index] = minimum + extra
330			allocated += extra
331		}
332		// Integer division can leave a few bytes. They are most valuable at the
333		// top of the ranking, where agents make their first navigation decision.
334		for index := 0; allocated < remaining; index = (index + 1) % count {
335			budgets[index]++
336			allocated++
337		}
338		return budgets
339	}
