341	func renderAgentSearchResults(results []sem.SearchResult, budgets []int) []byte {
342		var output bytes.Buffer
343		wrote := false
344		for index, result := range results {
345			budget := 0
346			if index < len(budgets) {
347				budget = budgets[index]
348			}
349			block := agentSearchBlock(result, budget)
350			if len(block) == 0 {
351				return nil
352			}
353			if wrote {
354				output.WriteByte('\n')
355			}
356			output.Write(block)
357			wrote = true
358		}
359		return output.Bytes()
360	}
