362	func agentSearchBlock(result sem.SearchResult, budget int) []byte {
363		name := result.QualifiedName
364		if name == "" {
365			name = result.SymbolName
366		}
367		lines := strings.Split(result.Snippet, "\n")
368		if len(lines) > 1 && lines[len(lines)-1] == "" {
369			lines = lines[:len(lines)-1]
370		}
371		snippetStart := result.SnippetStartLine
372		if snippetStart <= 0 {
373			snippetStart = result.StartLine
374		}
375		if snippetStart <= 0 {
376			snippetStart = 1
377		}
378		focusLine := result.FocusLine
379		if focusLine <= 0 {
380			focusLine = snippetStart
381		}
382		focus := focusLine - snippetStart
383		if focus < 0 || focus >= len(lines) {
384			focus = len(lines) / 2
385			focusLine = snippetStart + focus
386		}
387		if len(lines) == 0 {
388			return fitAgentSearchLocation(result.Rank, result.FilePath, focusLine, name, budget)
389		}
390	
391		// Prefer the widest balanced span containing the focus line. The location
392		// in the header is rebuilt for each candidate, so it always describes the
393		// lines actually displayed rather than the original untrimmed region.
394		for span := len(lines); span > 0; span-- {
395			leftMin := focus - span + 1
396			if leftMin < 0 {
397				leftMin = 0
398			}
399			leftMax := focus
400			if limit := len(lines) - span; leftMax > limit {
401				leftMax = limit
402			}
403			bestBalance := len(lines) + 1
404			var best []byte
405			for left := leftMin; left <= leftMax; left++ {
406				right := left + span - 1
407				text := strings.Join(lines[left:right+1], "\n")
408				startLine, endLine := snippetStart+left, snippetStart+right
409				for _, header := range agentSearchLocationHeaders(result.Rank, result.FilePath, startLine, endLine, focusLine, name) {
410					candidate := []byte(header + text + "\n")
411					if budget <= 0 || len(candidate) <= budget {
412						balance := focus - left - (right - focus)
413						if balance < 0 {
414							balance = -balance
415						}
416						if best == nil || balance < bestBalance {
417							best, bestBalance = candidate, balance
418						}
419						break
420					}
421				}
422			}
423			if best != nil {
424				return best
425			}
426		}
427		return fitAgentSearchLocation(result.Rank, result.FilePath, focusLine, name, budget)
428	}
429	
430	func agentSearchLocationHeaders(rank int, path string, start, end, focus int, name string) []string {
431		location := fmt.Sprintf("%d. %s:%d", rank, path, start)
432		if end != start {
433			location += fmt.Sprintf("-%d", end)
434		}
435		rich := location
436		if name != "" {
437			rich += " " + name
438		}
439		rich += fmt.Sprintf(" [focus:%d]\n", focus)
440		compact := location
441		if name != "" {
442			compact += " " + name
443		}
444		compact += " *\n"
445		minimal := fmt.Sprintf("%s:%d *\n", path, focus)
446		return []string{rich, compact, minimal}
447	}
448	
449	func fitAgentSearchLocation(rank int, path string, focus int, name string, budget int) []byte {
450		for _, header := range agentSearchLocationHeaders(rank, path, focus, focus, focus, name) {
451			if budget <= 0 || len(header) <= budget {
452				return []byte(header)
453			}
454		}
455		return nil
456	}
