	repo := t.TempDir()
	writeFile(t, repo, "src/types.ts", `
type input<T> = { data: T };

abstract class Base {
  abstract _parse(value: input<string>): void;

  _parseSync(value: input<string>): void {
    this._parse(value);
  }
